const staticData = $getWorkflowStaticData('global');
if (!Array.isArray(staticData.processedGmailIds)) staticData.processedGmailIds = [];
const processed = new Set(staticData.processedGmailIds);
const sdCfg = $getWorkflowStaticData('global');
const MAX = Math.min(50, Math.max(1, Number(sdCfg.gmailMaxPerRun || 25)));

function stripHtml(html) {
  return String(html || '')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/gi, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function parseFromHeader(from) {
  const raw =
    typeof from === 'string'
      ? from
      : from?.text || from?.value?.[0]?.name
        ? `${from.value[0].name} <${from.value[0].address}>`
        : from?.value?.[0]?.address || '';
  const s = String(raw || '').trim();
  const m = s.match(/<([^>]+)>/);
  const email = (m ? m[1] : s).trim().toLowerCase();
  const name = s.replace(/<[^>]+>/, '').replace(/"/g, '').trim();
  return { name, email };
}

function extractField(text, labels) {
  for (const label of labels) {
    const re = new RegExp(`(?:^|[\n\r])\\s*${label}\\s*[:：]\\s*([^\\n\r;|]+)`, 'im');
    const m = text.match(re);
    if (m && m[1]) return String(m[1]).trim();
  }
  return '';
}

function parseLeadFromEmail(msg) {
  const subject = String(msg.subject || '').trim();
  const body = String(
    msg.textPlain || msg.text || msg.snippet || stripHtml(msg.html) || '',
  ).trim();
  const full = `${subject}\n${body}`;

  let json = null;
  const jsonMatch = body.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    try {
      json = JSON.parse(jsonMatch[0]);
    } catch {
      json = null;
    }
  }

  const from = parseFromHeader(msg.from);
  let name = extractField(full, [
    'name',
    'full[\\s_]*name',
    'customer',
    'الاسم',
    'الاسم[\\s_]*الكامل',
    'اسم',
    'عميل',
  ]);
  let email = extractField(full, ['e-?mail', 'email', 'البريد', 'الايميل', 'إيميل', 'بريد']).toLowerCase();
  let phone = extractField(full, [
    'phone',
    'phone[\\s_]*number',
    'mobile',
    'tel',
    'الجوال',
    'الهاتف',
    'جوال',
    'موبايل',
    'هاتف',
  ]).replace(/\s+/g, '');
  let company = extractField(full, ['company', 'company[\\s_]*name', 'business', 'الشركة', 'شركة', 'مؤسسة']);

  if (json && typeof json === 'object') {
    name = name || String(json.name || json.full_name || json.fullName || '').trim();
    email = email || String(json.email || json.mail || '').trim().toLowerCase();
    phone = phone || String(json.phone || json.mobile || json.tel || '').replace(/\s+/g, '');
    company = company || String(json.company || json.company_name || '').trim();
  }

  if (!email && from.email) email = from.email;
  if (!name && from.name) name = from.name;
  if (!name) name = (subject || 'عميل بريد').slice(0, 120);
  if (!company) company = '—';

  const looksLikeLead =
    /lead|ليد|عميل|inquiry|استفسار|تسعير|quote|طلب|contact|تواصل/i.test(full) ||
    Boolean(phone) ||
    Boolean(email && email !== from.email);

  if (!looksLikeLead) return null;

  const msgId = String(msg.id || msg.messageId || '');
  if (!msgId) return null;

  if (!email && !phone) email = `gmail-${msgId}@email-lead.local`;
  if (!phone) phone = '01000000000';
  if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) email = `gmail-${msgId}@email-lead.local`;

  const received =
    msg.date || msg.internalDate
      ? new Date(msg.date || Number(msg.internalDate)).toISOString()
      : new Date().toISOString();

  return {
    gmail_message_id: msgId,
    gmail_subject: subject.slice(0, 300),
    gmail_from: from.email || '',
    name: name.slice(0, 200),
    company: company.slice(0, 200),
    phone,
    email,
    source: 'email',
    received_at: received,
  };
}

const out = [];
const newlyProcessed = [];

for (const item of $input.all()) {
  const msg = item.json || {};
  const msgId = String(msg.id || msg.messageId || '');
  if (!msgId || processed.has(msgId)) continue;

  const lead = parseLeadFromEmail(msg);
  newlyProcessed.push(msgId);
  if (!lead) continue;

  out.push({ json: lead });
  if (out.length >= MAX) break;
}

for (const id of newlyProcessed) {
  processed.add(id);
}
staticData.processedGmailIds = Array.from(processed).slice(-800);

if (out.length === 0) {
  return [
    {
      json: {
        _summary: true,
        parsed: 0,
        scanned: $input.all().length,
        message: 'No new lead emails to import.',
      },
    },
  ];
}

return out;

async function resolveSupabase() {
  let url = '';
  let key = '';
  try {
    const sb = await this.getCredentials('supabaseApi');
    url = String(sb.host || sb.url || '').replace(/\/$/, '');
    key = String(sb.serviceRole || sb.serviceRoleKey || '').trim();
  } catch (_) {}
  if (!url) url = String($env.SUPABASE_URL || '').replace(/\/$/, '');
  if (!key) key = String($env.SUPABASE_SERVICE_ROLE_KEY || '').trim();
  if (!url || !key) {
    throw new Error('ربط Supabase: اختر Credential نوع Supabase API (Host + Service Role) على عقدة Insert، أو Environment.');
  }
  return { url, key };
}
const { url: SUPABASE_URL, key: KEY } = await resolveSupabase.call(this);
const sd = $getWorkflowStaticData('global');
const ASSIGNED = sd.defaultAssignedToId || $env.DEFAULT_ASSIGNED_TO_ID || null;

const headers = {
  apikey: KEY,
  Authorization: `Bearer ${KEY}`,
  'Content-Type': 'application/json',
};

function makeId() {
  return `lead_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 10)}`;
}

const items = $input.all().filter((i) => !i.json._summary);
const results = [];
let inserted = 0;
let skipped = 0;
let errors = 0;

for (const item of items) {
  const lead = item.json;
  const email = lead.email;
  const phone = lead.phone;

  let existing;
  try {
    const checkUrl = `${SUPABASE_URL}/rest/v1/leads?or=(email.eq.${encodeURIComponent(email)},phone.eq.${encodeURIComponent(phone)})&select=id&limit=1`;
    existing = await this.helpers.httpRequest({ method: 'GET', url: checkUrl, headers, json: true });
  } catch (e) {
    errors += 1;
    results.push({ json: { ...lead, status: 'error', step: 'duplicate_check', message: e.message } });
    continue;
  }

  if (Array.isArray(existing) && existing.length > 0) {
    skipped += 1;
    results.push({ json: { ...lead, status: 'skipped_duplicate', existing_id: existing[0].id } });
    continue;
  }

  const id = makeId();
  const now = new Date().toISOString();
  const createdAt = lead.received_at || now;
  const timeline = [
    {
      id: `ev-gmail-${id}`,
      leadId: id,
      action: 'استيراد من Gmail (n8n)',
      note: `Gmail ID: ${lead.gmail_message_id} — ${lead.gmail_subject || ''}`,
      userId: 'n8n',
      userName: 'تكامل البريد',
      createdAt,
    },
    {
      id: `a-${id}`,
      leadId: id,
      action: 'إضافة الليد إلى النظام',
      userId: 'n8n',
      userName: 'تكامل البريد',
      createdAt: now,
    },
  ];

  const row = {
    id,
    customer_code: null,
    name: lead.name,
    company: lead.company,
    phone: lead.phone,
    email: lead.email,
    status: 'جديد',
    assigned_to_id: ASSIGNED,
    budget: 0,
    company_size: 'صغير',
    source: 'email',
    category: 'إعلانات',
    score: 50,
    follow_up_at: null,
    loss_reason_code: null,
    sla_status: 'مستقر',
    timeline_json: timeline,
    created_at: createdAt,
    updated_at: now,
  };

  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: `${SUPABASE_URL}/rest/v1/leads`,
      headers: { ...headers, Prefer: 'return=minimal' },
      body: row,
    });
    inserted += 1;
    results.push({ json: { ...lead, status: 'inserted', lead_id: id } });
  } catch (e) {
    errors += 1;
    results.push({ json: { ...lead, status: 'error', step: 'insert', message: e.message } });
  }
}

results.push({
  json: {
    _summary: true,
    processed: items.length,
    inserted,
    skipped_duplicate: skipped,
    errors,
  },
});

return results;
